llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
  auto& irb = *mCurIrb;
  auto lft = self(obj->lft);
  auto rht = self(obj->rht);

  switch (obj->op) {
    case BinaryExpr::kAdd:
      return irb.CreateAdd(lft, rht);
    case BinaryExpr::kSub:
      return irb.CreateSub(lft, rht);
    case BinaryExpr::kMul:
      return irb.CreateMul(lft, rht);
    case BinaryExpr::kDiv:
      return irb.CreateSDiv(lft, rht);
    case BinaryExpr::kMod:
      return irb.CreateSRem(lft, rht);
    case BinaryExpr::kAssign:
      if (auto declRef = obj->lft->dcst<DeclRefExpr>()) {
        auto ptr = llvm::dyn_cast<llvm::GlobalValue>(declRef->decl->any);
        if (!ptr) {
          ptr = llvm::dyn_cast<llvm::AllocaInst>(declRef->decl->any);
        }
        irb.CreateStore(rht, ptr);
        return rht;
      }
      ABORT();
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
  if (auto global = llvm::dyn_cast<llvm::GlobalValue>(obj->decl->any)) {
    return mCurIrb->CreateLoad(global->getValueType(), global);
  }
  if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(obj->decl->any)) {
    return mCurIrb->CreateLoad(alloca->getAllocatedType(), alloca);
  }
  ABORT();
}

